// Roll five weighted, explainable factors into one per-leg risk score.
// Pure function: no network/closure deps, so it is directly unit-testable
// (called exactly like computeLegWarnings via functions.call).
//
// bearing:      leg course over ground (degrees, direction of travel).
// hourData:     arrival-hour forecast { windSpeed, windDirection, windGusts,
//               precipitation, cloudCover, pressure }.
// prevHourData: forecast at the hour before arrival (for pressure trend), or null.
// arriveUtcMs:  the leg's estimated arrival time, UTC ms.
// sunsetUtcMs / sunriseUtcMs: that destination/day's sun times, UTC ms, or null.
// etaContext:   { cumulativeHoursToArrival, durationHours } — time-into-the-future.
// weights:      tunable thresholds/caps (headwind*, strongWindKnots, lowVis*,
//               pressure*, etaBasePct, etaHeadwindMult).
//
// Returns LegRiskScore { score(0..100), level, headline, factors[5] } where
// every factor carries { key, label, icon, points, max, detail }. Higher = riskier.
function computeLegRiskScore(
  bearing: number,
  hourData: any,
  prevHourData: any,
  arriveUtcMs: number,
  sunsetUtcMs: number | null,
  sunriseUtcMs: number | null,
  etaContext: any,
  weights: any
) {
  // --- Tunables with defensive defaults so a missing config never throws ---
  const w = weights || {};
  const headwindAngleDeg = typeof w.headwindAngleDeg === 'number' ? w.headwindAngleDeg : 60;
  const headwindMinKnots = typeof w.headwindMinKnots === 'number' ? w.headwindMinKnots : 10;
  const strongWindKnots = typeof w.strongWindKnots === 'number' ? w.strongWindKnots : 22;
  const lowVisPrecipMm = typeof w.lowVisPrecipMm === 'number' ? w.lowVisPrecipMm : 2;
  const lowVisCloudPct = typeof w.lowVisCloudPct === 'number' ? w.lowVisCloudPct : 95;
  const pressureLowHpa = typeof w.pressureLowHpa === 'number' ? w.pressureLowHpa : 1005;
  const pressureDropHpa = typeof w.pressureDropHpa === 'number' ? w.pressureDropHpa : 3;
  const etaBasePct = typeof w.etaBasePct === 'number' ? w.etaBasePct : 6;
  const etaHeadwindMult = typeof w.etaHeadwindMult === 'number' ? w.etaHeadwindMult : 1.8;

  // Factor weight caps — they sum to 100 so the rolled score is naturally 0..100
  const WIND_MAX = 30, VIS_MAX = 20, PRESSURE_MAX = 20, SUNSET_MAX = 15, ETA_MAX = 15;

  // Small local helpers (kept inline to preserve purity)
  const clamp = (n: number, lo: number, hi: number) => Math.max(lo, Math.min(hi, n));
  const round1 = (n: number) => Math.round(n * 10) / 10;
  const angularDiff = (a: number, b: number) => {
    const d = Math.abs((((a - b) % 360) + 360) % 360);
    return d > 180 ? 360 - d : d;
  };

  // --- Resolve forecast numbers defensively (missing => benign) ---
  const h = hourData || {};
  const windSpeed = typeof h.windSpeed === 'number' ? h.windSpeed : 0;
  const windGusts = typeof h.windGusts === 'number' ? h.windGusts : windSpeed;
  const windDir = typeof h.windDirection === 'number' ? h.windDirection : null;
  const precip = typeof h.precipitation === 'number' ? h.precipitation : 0;
  const cloud = typeof h.cloudCover === 'number' ? h.cloudCover : 0;
  const pressure = typeof h.pressure === 'number' ? h.pressure : null;

  // Shared classifications reused by the wind + ETA factors
  const isHeadwind = windDir !== null
    && angularDiff(windDir, bearing) <= headwindAngleDeg
    && windSpeed >= headwindMinKnots;
  const isStrongWind = windSpeed >= strongWindKnots;

  // ===== Factor 1: Wind (cap 30) =====
  // Speed ramps to ~18 pts by 30 kn; a headwind and gust spread add the rest.
  const speedPts = clamp((windSpeed / 30) * 18, 0, 18);
  const headwindPts = isHeadwind ? 7 : 0;
  const gustSpread = Math.max(0, windGusts - windSpeed);
  const gustPts = clamp((gustSpread / 12) * 5, 0, 5);
  const windPoints = Math.round(clamp(speedPts + headwindPts + gustPts, 0, WIND_MAX));
  let windDetail: string;
  if (windPoints === 0) {
    windDetail = 'Light wind (' + Math.round(windSpeed) + ' kn)';
  } else {
    windDetail = Math.round(windSpeed) + ' kn';
    if (isStrongWind) windDetail += ' (strong)';
    if (isHeadwind) windDetail += ', headwind';
    if (gustSpread >= 4) windDetail += ', gusts ' + Math.round(windGusts) + ' kn';
  }

  // ===== Factor 2: Visibility (cap 20) =====
  // Heavy precip and near-total cloud both reduce visibility (fog/squall proxy).
  const precipPts = clamp((precip / (lowVisPrecipMm * 2)) * 14, 0, 14);
  const cloudPts = clamp(((cloud - 50) / 50) * 8, 0, 8);
  const visPoints = Math.round(clamp(precipPts + cloudPts, 0, VIS_MAX));
  let visDetail: string;
  if (visPoints === 0) {
    visDetail = 'Clear visibility';
  } else {
    const parts: string[] = [];
    if (precip > 0) parts.push(round1(precip) + ' mm/h precip');
    if (cloud >= 60) parts.push(Math.round(cloud) + '% cloud');
    visDetail = parts.length ? parts.join(', ') : 'Reduced visibility';
  }

  // ===== Factor 3: Pressure (cap 20) =====
  // A low absolute pressure and/or a sharp hour-over-hour fall signal weather.
  let lowAbsPts = 0;
  if (pressure !== null) lowAbsPts = clamp(pressureLowHpa - pressure, 0, 12);
  let drop = 0;
  if (pressure !== null && prevHourData && typeof prevHourData.pressure === 'number') {
    drop = prevHourData.pressure - pressure;
  }
  const fallPts = clamp((drop / pressureDropHpa) * 8, 0, 8);
  const pressurePoints = Math.round(clamp(lowAbsPts + fallPts, 0, PRESSURE_MAX));
  let pressureDetail: string;
  if (pressure === null) {
    pressureDetail = 'Pressure unavailable';
  } else if (pressurePoints === 0) {
    pressureDetail = 'Steady ' + Math.round(pressure) + ' hPa';
  } else {
    const parts: string[] = [];
    if (pressure <= pressureLowHpa) parts.push('low ' + Math.round(pressure) + ' hPa');
    if (drop > 0) parts.push('falling ' + round1(drop) + ' hPa/h');
    pressureDetail = parts.length ? parts.join(', ') : Math.round(pressure) + ' hPa';
  }

  // ===== Factor 4: Sunset / darkness (cap 15) =====
  // Arriving in darkness is full risk; arriving near dusk is partial.
  const hasArrive = typeof arriveUtcMs === 'number' && isFinite(arriveUtcMs);
  const sunsetKnown = typeof sunsetUtcMs === 'number' || typeof sunriseUtcMs === 'number';
  const afterSunset = hasArrive && typeof sunsetUtcMs === 'number' && arriveUtcMs >= sunsetUtcMs;
  const beforeSunrise = hasArrive && typeof sunriseUtcMs === 'number' && arriveUtcMs <= sunriseUtcMs;
  const DUSK_MS = 45 * 60000; // arrivals within 45 min before sunset count as dusk
  let sunsetPoints = 0;
  let sunsetDetail: string;
  if (!hasArrive || !sunsetKnown) {
    sunsetDetail = 'Sun times unavailable';
  } else if (afterSunset || beforeSunrise) {
    sunsetPoints = SUNSET_MAX;
    sunsetDetail = beforeSunrise ? 'Arrives before sunrise (darkness)' : 'Arrives after sunset (darkness)';
  } else if (typeof sunsetUtcMs === 'number' && (sunsetUtcMs - arriveUtcMs) >= 0 && (sunsetUtcMs - arriveUtcMs) <= DUSK_MS) {
    sunsetPoints = 8;
    sunsetDetail = 'Arrives near dusk';
  } else {
    sunsetDetail = 'Daylight arrival';
  }

  // ===== Factor 5: ETA uncertainty (cap 15) =====
  // The constant-speed ETA gets less trustworthy the further into the future the
  // arrival is, and degrades further into a headwind or in strong wind.
  const etaCtx = etaContext || {};
  const cumulativeHours = (typeof etaCtx.cumulativeHoursToArrival === 'number' && isFinite(etaCtx.cumulativeHoursToArrival))
    ? Math.max(0, etaCtx.cumulativeHoursToArrival) : 0;
  let windMult = 1;
  if (isHeadwind) windMult *= etaHeadwindMult;
  if (isStrongWind) windMult *= 1.4;
  const driftMinutes = cumulativeHours * 60 * (etaBasePct / 100) * windMult;
  const etaPoints = Math.round(clamp((driftMinutes / 90) * ETA_MAX, 0, ETA_MAX));
  let etaDetail: string;
  if (cumulativeHours <= 0) {
    etaDetail = 'Immediate arrival, ETA reliable';
  } else {
    etaDetail = '±' + Math.round(driftMinutes) + ' min drift over ' + round1(cumulativeHours) + ' h';
    if (isHeadwind && isStrongWind) etaDetail += ' (headwind + strong wind)';
    else if (isHeadwind) etaDetail += ' (headwind)';
    else if (isStrongWind) etaDetail += ' (strong wind)';
  }

  // --- Assemble explainable factors (integer points so segments sum to score) ---
  const factors = [
    { key: 'wind', label: 'Wind', icon: '💨', points: windPoints, max: WIND_MAX, detail: windDetail },
    { key: 'visibility', label: 'Visibility', icon: '🌫️', points: visPoints, max: VIS_MAX, detail: visDetail },
    { key: 'pressure', label: 'Pressure', icon: '📉', points: pressurePoints, max: PRESSURE_MAX, detail: pressureDetail },
    { key: 'sunset', label: 'Sunset', icon: '🌙', points: sunsetPoints, max: SUNSET_MAX, detail: sunsetDetail },
    { key: 'eta', label: 'ETA uncertainty', icon: '⏱️', points: etaPoints, max: ETA_MAX, detail: etaDetail }
  ];

  // Roll-up: integer factor points sum to a 0..100 score (caps total 100)
  const score = clamp(factors.reduce((s: number, f: any) => s + f.points, 0), 0, 100);

  // 4-tier level from the rolled score
  let level = 'low';
  if (score >= 70) level = 'severe';
  else if (score >= 45) level = 'high';
  else if (score >= 20) level = 'moderate';

  // Headline naming the dominant contributor (for a one-line explanation)
  let top = factors[0];
  for (const f of factors) if (f.points > top.points) top = f;
  const levelLabel = level.charAt(0).toUpperCase() + level.slice(1);
  let headline: string;
  if (score === 0) headline = 'Calm — negligible risk';
  else if (top.points <= 0) headline = levelLabel + ' risk';
  else headline = levelLabel + ' risk — mainly ' + top.label.toLowerCase();

  return { score, level, headline, factors };
}
